    function json_schema_validator($data, $schema, $return_errors = null, $timeout = null)
    {
        // JSON Schema Validator — Draft 2020-12 compatible
        // Validates PHP data structures against JSON Schema with detailed error paths

        $timeout = min(15, max(1, $timeout ?? 10));
