                    $actualType = gettype($value);
                    // Map PHP types to JSON types
                    $jsonType = $actualType;
                    if ($actualType === 'boolean') $jsonType = 'boolean';
                    elseif ($actualType === 'integer') $jsonType = 'integer';
                    elseif ($actualType === 'double') $jsonType = 'number';
                    elseif ($actualType === 'string') $jsonType = 'string';
                    elseif ($actualType === 'array') {
