                        if ($t === 'integer' && is_int($value)) { $typeMatch = true; break; }
                        if ($t === 'string' && is_string($value)) { $typeMatch = true; break; }
                        if ($t === 'boolean' && is_bool($value)) { $typeMatch = true; break; }
                        if ($t === 'array' && is_array($value) && array_keys($value) === range(0, count($value)-1)) { $typeMatch = true; break; }
                        if ($t === 'object' && (is_array($value) && !empty($value) && array_keys($value) !== range(0, count($value)-1))) { $typeMatch = true; break; }
                        if ($t === 'object' && is_object($value)) { $typeMatch = true; break; }
                        if ($t === 'null' && $value === null) { $typeMatch = true; break; }
                        if ($t === 'null' && $actualType === 'NULL') { $typeMatch = true; break; }
                    }
                    if (!$typeMatch && !($nullable && $value === null)) {
