                    return true;
                }

                // --- String constraints ---
                if (is_string($value)) {
                    // minLength / maxLength
                    if (isset($sch['minLength']) && mb_strlen($value) < $sch['minLength']) {
                        $errors[] = ['path' => $path, 'error' => "String length " . mb_strlen($value) . " is less than minLength {$sch['minLength']}"];
