                    }
                    // format
                    if (isset($sch['format'])) {
                        $fmt = $sch['format'];
                        $fmtValid = true;
                        switch ($fmt) {
                            case 'date':
                                $fmtValid = (bool)preg_match('/^\d{4}-\d{2}-\d{2}$/', $value);
                                break;
                            case 'time':
                                $fmtValid = (bool)preg_match('/^\d{2}:\d{2}(:\d{2})?(\.\d+)?(Z|[+-]\d{2}:\d{2})?$/', $value);
