                if (isset($sch['not']) && is_array($sch['not'])) {
                    $subErrors = [];
                    $savedErrors = $errors;
                    $errors = [];
                    $valid = $validate($value, $sch['not'], $path);
                    $errors = $savedErrors;
                    if ($valid) {
                        $errors[] = ['path' => $path, 'error' => "Value matches 'not' schema (should NOT match)"];
                        return false;
                    }
                }

                // Check for subschema evaulation errors
                return true;
            };

            // Run validation
            $validate($parsed, $schemaArr, '');

            $valid = empty($errors);

            $result = ['valid' => $valid];
            if ($returnErrors && !empty($errors)) {
                $result['errors'] = $errors;
                $result['error_count'] = count($errors);
            }
            $result['path'] = '';

            return $result;

        } catch (\Exception $e) {
            return ['valid' => false, 'error' => $e->getMessage(), 'path' => ''];
